{
  "verses": [
    {
      "n": 9,
      "column": "left",
      "text": "Tee zaur fauw Augstibn\npadarra tohs Apbehdinatus breh-\nzain/ ka tee fauz to Augstaku\nElkona deht.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Bet ne weenstaken : Kur\nirr Deews mans Radditajs? kas\n(tik dauds) dohd / ka winnam\nNakti par to buhs dseedaht.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Kas innhs jo ismahzitus\ndarra/ ne ka tohs Lohpus wirs\nSeines/ un gudrakus ne ka tohs\nPutnus appatsch Debbesim.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Tee tur brehks/ bet wiꞥſch\nne atbildes to Launu Lepni-\nbas deht.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Teefcham/ tas STIP-\nRAJS DEEWS to neleetu\nBuhfchanu ne paklausfhs/ un tas\nWiffuwarrenajs to ne uslubfohs.\n"
    },
    {
      "n": 14,
      "column": "left",
      "text": "Ir tu fakki/ ka tu winnu\nne redfeſi/ bet weena Teeza irr\npreekſch winna Waiga/ gaidi tu\nween us winnu.\n"
    },
    {
      "n": 15,
      "column": "left",
      "text": "Un uu/ tapehz ka winna\nDufiniba (tikdrihsi) ne peemek-\nle/ un wehra ne leek/ ka tik dauds\nPahrkahpchanas irr/\n"
    },
    {
      "n": 16,
      "column": "left",
      "text": "Tad irr Jjabs fauw\nMutti welti atwehris/ un bes\nwiffas Sinnaschanas dauds\nWahrdus runnajs.\n"
    },
    {
      "n": 1,
      "column": "left",
      "text": "N Elijus runnaja wehl\nvatrak/ un fazzia?\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Pagaidi man wehl Deenas eekſch Labbuma pabeigs\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "mas/ es tew to paradifchu/\nno Deewa Puffes wehl kas\nrunna.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Es dabbuschu fauw Q\nprafchann no tahkenes/ un pee\nfchu mannarn Darritajam T\nnibu.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Jo teefcham/ manna W\nloda ne buhs wiltiga/ pee t\nbuhs tahds/ kam skaidrs Bra\nirr.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Rangi/ tas STI-\nRAJS DEEWS irr w\nrens/ un ne attinett/ wiꞥſch\nwarrens ar firdign Spehku.\n"
    },
    {
      "n": 6,
      "column": "right",
      "text": "Wiꞥſch ue leek to Besd\nwigu dsihwoht/ un neff tee\nBehdigeem to Teefu.\n"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Wiꞥſch ne atrauj fauw\nAzzis no ta Taifna/ un pee tee\nFehnikeein irr wiꞥſch us Gohd\nKrehflu/ un leek tohs tur fehde\nmuhſcham/ ka tee tohp pa-an\nstinati.\n"
    },
    {
      "n": 8,
      "column": "right",
      "text": "Un kur Zeetuma Laud\nirr ar Schkehdehm faistiti/\ntohp ar behdigahm Saiteh\n"
    },
    {
      "n": 9,
      "column": "right",
      "text": "Tad pasluddina wiꞥſ-\nteem winnu Darbu/ un winn\nPahrkahpschanas/ ka tahs wa-\nren leelas tappufchas.\n"
    },
    {
      "n": 10,
      "column": "right",
      "text": "Wiꞥſch atdarra teem t\nAnti pee Panmahzitchanas/ u\ntakka: Lai tee no Netaifnibas a\n"
    },
    {
      "n": 11,
      "column": "right",
      "text": "Ja tee nu klaufa / u\n(winnam) kalpo/ tad tee fauw\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
